#ifndef BLOCK_SIZE
#define BLOCK_SIZE 16
#endif

#define AA(_i,_j) a[offset*size+_i*size+_j+offset]
#define BB(_i,_j) a[_i*size+_j]

kernel void lud_diagonal(global float* a, local float* temp, const int size, const int offset)
{
    int i = get_global_id(0);
    int j, k;
    float sum;

    if (i >= BLOCK_SIZE) return;

    for (j = i; j < BLOCK_SIZE; j++) {
        sum = AA(i, j);
        for (k = 0; k < i; k++) {
            sum -= AA(i, k) * AA(k, j);
        }
        AA(i, j) = sum;
    }

    if (i == 0) {
        float temp_diag[BLOCK_SIZE];
        for (j = 0; j < BLOCK_SIZE; j++) {
            temp_diag[j] = AA(j, j);
        }

        for (i = 0; i < BLOCK_SIZE; i++) {
            for (j = i + 1; j < BLOCK_SIZE; j++) {
                sum = AA(j, i);
                for (k = 0; k < i; k++) {
                    sum -= AA(j, k) * AA(k, i);
                }
                AA(j, i) = sum / temp_diag[i];
            }
        }
    }
}

kernel void lud_perimeter(global float* a, local float* temp_right, local float* temp_bottom, local float* temp_diag, const int size, const int offset)
{
    int idx = get_global_id(0);
    int local_id = get_local_id(0);
    int i, j, k;
    float sum;

    int size_inter = size - offset - BLOCK_SIZE;
    int chunks_in_inter_row = size_inter / BLOCK_SIZE;

    if (chunks_in_inter_row <= 0) return;

    int total_perimeter = chunks_in_inter_row * BLOCK_SIZE * 2;
    if (idx >= total_perimeter) return;

    if (idx < chunks_in_inter_row * BLOCK_SIZE) {
        int chunk_idx = idx / BLOCK_SIZE;
        int row_idx = idx % BLOCK_SIZE;

        int j_global = offset + BLOCK_SIZE * (chunk_idx + 1);

        for (i = 0; i < BLOCK_SIZE; i++) {
            temp_diag[i * BLOCK_SIZE + local_id] = a[size * (i + offset) + offset + local_id];
        }

        for (j = 0; j < BLOCK_SIZE; j++) {
            sum = 0.0f;
            for (k = 0; k < BLOCK_SIZE; k++) {
                if (k < row_idx) {
                    sum += temp_diag[row_idx * BLOCK_SIZE + k] * BB(offset + k, j_global + j);
                }
            }
            BB(offset + row_idx, j_global + j) -= sum;
        }
    } else {
        int adjusted_idx = idx - chunks_in_inter_row * BLOCK_SIZE;
        int chunk_idx = adjusted_idx / BLOCK_SIZE;
        int col_idx = adjusted_idx % BLOCK_SIZE;

        int i_global = offset + BLOCK_SIZE * (chunk_idx + 1);

        for (j = 0; j < BLOCK_SIZE; j++) {
            temp_diag[col_idx * BLOCK_SIZE + j] = a[size * (offset + col_idx) + offset + j];
        }

        for (i = 0; i < BLOCK_SIZE; i++) {
            sum = 0.0f;
            for (k = 0; k < BLOCK_SIZE; k++) {
                if (k < col_idx) {
                    sum += BB(i_global + i, offset + k) * temp_diag[k * BLOCK_SIZE + col_idx];
                }
            }
            BB(i_global + i, offset + col_idx) = (BB(i_global + i, offset + col_idx) - sum) / BB(offset + col_idx, offset + col_idx);
        }
    }
}

kernel void lud_internal(global float* a, local float* temp_top, local float* temp_left, const int size, const int offset)
{
    int block_row = get_global_id(0) / BLOCK_SIZE;
    int block_col = get_global_id(1) / BLOCK_SIZE;
    int local_row = get_local_id(0);
    int local_col = get_local_id(1);

    int size_inter = size - offset - BLOCK_SIZE;
    int chunks_in_inter_row = size_inter / BLOCK_SIZE;

    if (block_row >= chunks_in_inter_row || block_col >= chunks_in_inter_row) return;

    int i_global = offset + BLOCK_SIZE * (block_row + 1);
    int j_global = offset + BLOCK_SIZE * (block_col + 1);

    int i, j, k;

    for (i = 0; i < BLOCK_SIZE; i++) {
        for (j = 0; j < BLOCK_SIZE; j++) {
            temp_top[i * BLOCK_SIZE + j] = a[size * (i + offset) + j_global + j];
            temp_left[i * BLOCK_SIZE + j] = a[size * (i_global + i) + offset + j];
        }
    }

    for (i = 0; i < BLOCK_SIZE; i++) {
        float sum[BLOCK_SIZE];
        for (j = 0; j < BLOCK_SIZE; j++) {
            sum[j] = 0.0f;
        }

        for (k = 0; k < BLOCK_SIZE; k++) {
            for (j = 0; j < BLOCK_SIZE; j++) {
                sum[j] += temp_left[i * BLOCK_SIZE + k] * temp_top[k * BLOCK_SIZE + j];
            }
        }

        for (j = 0; j < BLOCK_SIZE; j++) {
            BB(i_global + i, j_global + j) -= sum[j];
        }
    }
}
